+func severityRank(level ImpactLevel) int {
+	switch level {
+	case ImpactCritical:
+		return 4
+	case ImpactHigh:
+		return 3
+	case ImpactMedium:
+		return 2
+	case ImpactLow:
+		return 1
+	default:
+		return 2
+	}
+}
