+			name:    "same file distant lines",
+			a:       "file.go:10",
+			b:       "file.go:100",
+			wantMin: 0.2,
+			wantMax: 0.4,
+		},
+		{
+			name:    "different files",
+			a:       "file1.go:10",
+			b:       "file2.go:10",
+			wantMin: 0.0,
+			wantMax: 0.0,
